import { GoogleGenAI } from "@google/genai";
import { ClientProfile, InsightResponse } from "../types";

// Always create a fresh instance with process.env.API_KEY directly for each call to ensure reliability.
export const generateClientInsight = async (client: ClientProfile): Promise<InsightResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const agQuality = client.multiChannelQuality.find(q => q.channel.includes('AG')) || client.multiChannelQuality[0];
  const douyinQuality = client.multiChannelQuality.find(q => q.channel === '抖音');

  const prompt = `
    请作为应用分发广告平台（类似华为AppGallery或小米应用商店）的顶级广告分析专家。
    分析以下广告主的全方位数据：

    1. 客户档案: ${client.name} | 行业: ${client.industry} | 级别: ${client.tier}级 | 账户余额可用天数: ${client.financials.walletRunwayDays}
    2. 消耗表现: 今日预算利用率 ${client.budgetUtilization}% | 消耗节奏: ${client.spendVelocity} | 因预算丢失曝光: ${client.lostImpressionsByBudget}%
    3. 转化漏斗: 曝光到付费转化率分布在全链路 ${client.funnel.map(f => f.stage + ':' + f.rate + '%').join(', ')}
    4. 渠道对比: 
       - AG平台 (本平台): 下载量 ${(agQuality.downloads/10000).toFixed(1)}w, 次留 ${agQuality.retention1d}%
       - 抖音 (主要竞对): 下载量 ${(douyinQuality?.downloads ? douyinQuality.downloads/10000 : 0).toFixed(1)}w, 次留 ${douyinQuality?.retention1d}%
    5. 细分人群差距: ${client.segmentGaps.map(s => `${s.segment}(AG:${s.ag} vs 抖音:${s.douyin})`).join('; ')}
    6. 风险预警: 7日流失概率 ${client.churnProbability7d}% | CPA偏离度: ${client.cpaAnomaly.deviation}% | 预算瓶颈: ${client.budgetBottleneck}

    任务：
    1. 生成 1 句高管摘要，直指 AG 平台在特定人群中的优势或劣势，以及整体增长机会。
    2. 提供 3 项高价值的行动建议，必须覆盖预算调整、素材优化、人群定向或归因分析。
    3. 提供一个基于目前趋势的未来 14 天战略预测。

    输出格式: JSON 格式，包含 "summary", "actionItems" (数组), "prediction"。内容全部中文。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json'
      }
    });

    const text = response.text?.trim() || '{}';
    return JSON.parse(text) as InsightResponse;
  } catch (error) {
    console.error("Gemini Insight Error:", error);
    return {
      summary: "由于数据流波动，无法生成精准 AI 洞察。但初步观察显示，AG 平台在重度玩家人群中渗透率有待提升。",
      actionItems: ["检查高潜人群的定向出价是否过低", "对比抖音端高点击素材，优化 AG 详情页素材", "针对余额预警客户启动自助充值引导"],
      prediction: "预计未来两周行业竞争加剧，建议在保持现有 CPA 水平下，通过增加定向标签获取增量。"
    };
  }
};

import React from 'react';
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  BarChart,
  Bar,
  Cell,
  PieChart,
  Pie,
  LineChart,
  Line,
} from 'recharts';
// Fixed: Removed non-existent CompetitorData import
import { MetricPoint } from '../types';

interface TrendChartProps {
  data: MetricPoint[];
  dataKey: string;
  color: string;
  showForecast?: boolean;
}

export const TrendChart: React.FC<TrendChartProps> = ({ data, dataKey, color, showForecast }) => {
  return (
    <ResponsiveContainer width="100%" height={250}>
      <AreaChart data={data} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
        <defs>
          <linearGradient id={`color${dataKey}`} x1="0" y1="0" x2="0" y2="1">
            <stop offset="5%" stopColor={color} stopOpacity={0.8}/>
            <stop offset="95%" stopColor={color} stopOpacity={0}/>
          </linearGradient>
        </defs>
        <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{fontSize: 10}} />
        <YAxis axisLine={false} tickLine={false} tick={{fontSize: 10}} />
        <CartesianGrid vertical={false} strokeDasharray="3 3" stroke="#f0f0f0" />
        <Tooltip 
          contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
        />
        <Area 
          type="monotone" 
          dataKey="value" 
          stroke={color} 
          fillOpacity={1} 
          fill={`url(#color${dataKey})`} 
          name="数值"
        />
        {showForecast && (
             <Area 
             type="monotone" 
             dataKey="forecast" 
             stroke={color} 
             strokeDasharray="5 5"
             fill="none"
             name="预测值"
           />
        )}
      </AreaChart>
    </ResponsiveContainer>
  );
};

export const MultiLineChart: React.FC<{data: any[], lines: any[]}> = ({ data, lines }) => {
  return (
    <ResponsiveContainer width="100%" height={250}>
      <LineChart data={data}>
        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
        <XAxis dataKey="date" tick={{fontSize: 10}} />
        <YAxis tick={{fontSize: 10}} />
        <Tooltip />
        <Legend />
        {lines.map((line) => (
          <Line key={line.key} type="monotone" dataKey={line.key} stroke={line.color} strokeWidth={2} name={line.name} dot={{r: 3}} />
        ))}
      </LineChart>
    </ResponsiveContainer>
  );
};

export const DonutChart: React.FC<{data: any[], height?: number}> = ({ data, height = 250 }) => {
  return (
    <ResponsiveContainer width="100%" height={height}>
      <PieChart>
        <Pie
          data={data}
          innerRadius={height * 0.25}
          outerRadius={height * 0.35}
          paddingAngle={5}
          dataKey="value"
          nameKey="label"
          label={({ label, value }) => `${label} (${value}%)`}
        >
          {data.map((entry, index) => (
            <Cell key={`cell-${index}`} fill={entry.color} />
          ))}
        </Pie>
        <Tooltip 
          formatter={(value: number, name: string, props: any) => {
             const count = props.payload.count;
             return [`${value}% (${count ? (count/10000).toFixed(1) + 'w' : ''})`, name];
          }}
          contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
        />
        <Legend 
            verticalAlign="bottom"
            formatter={(value) => {
                const item = data.find(d => d.label === value);
                return <span className="text-gray-600 text-xs font-medium">{value} ({item?.value}%)</span>;
            }}
        />
      </PieChart>
    </ResponsiveContainer>
  );
};

export const FunnelChart: React.FC<{data: any[]}> = ({ data }) => {
  return (
    <ResponsiveContainer width="100%" height={250}>
      <BarChart layout="vertical" data={data}>
        <XAxis type="number" hide />
        <YAxis dataKey="stage" type="category" tick={{fontSize: 12}} />
        <Tooltip />
        <Bar dataKey="value" fill="#6366f1" barSize={25} />
      </BarChart>
    </ResponsiveContainer>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { ClientProfile, InsightResponse } from "../types";

/**
 * Generates automated advertising insights using Gemini 3 models.
 * Implementation adheres to @google/genai best practices for initialization and JSON output.
 */
export const generateClientInsight = async (client: ClientProfile): Promise<InsightResponse> => {
  // Always create a fresh instance with process.env.API_KEY directly for each call.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const agQuality = client.multiChannelQuality.find(q => q.channel.includes('AG')) || client.multiChannelQuality[0];
  const douyinQuality = client.multiChannelQuality.find(q => q.channel === '抖音');

  const prompt = `
    请作为应用分发广告平台（类似华为AppGallery或小米应用商店）的顶级广告分析专家。
    分析以下广告主的全方位数据：

    1. 客户档案: ${client.name} | 行业: ${client.industry} | 级别: ${client.tier}级 | 账户余额可用天数: ${client.financials.walletRunwayDays}
    2. 消耗表现: 今日预算利用率 ${client.budgetUtilization}% | 消耗节奏: ${client.spendVelocity} | 因预算丢失曝光: ${client.lostImpressionsByBudget}%
    3. 转化漏斗: 曝光到付费转化率分布在全链路 ${client.funnel.map(f => f.stage + ':' + f.rate + '%').join(', ')}
    4. 渠道对比: 
       - AG平台 (本平台): 下载量 ${(agQuality.downloads/10000).toFixed(1)}w, 次留 ${agQuality.retention1d}%
       - 抖音 (主要竞对): 下载量 ${(douyinQuality?.downloads ? douyinQuality.downloads/10000 : 0).toFixed(1)}w, 次留 ${douyinQuality?.retention1d}%
    5. 细分人群差距: ${client.segmentGaps.map(s => `${s.segment}(AG:${s.ag} vs 抖音:${s.douyin})`).join('; ')}
    6. 风险预警: 7日流失概率 ${client.churnProbability7d}% | CPA偏离度: ${client.cpaAnomaly.deviation}% | 预算瓶颈: ${client.budgetBottleneck}

    任务：
    1. 生成 1 句高管摘要，直指 AG 平台在特定人群中的优势或劣势，以及整体增长机会。
    2. 提供 3 项高价值的行动建议，必须覆盖预算调整、素材优化、人群定向或归因分析。
    3. 提供一个基于目前趋势的未来 14 天战略预测。

    输出格式: JSON 格式，包含 "summary", "actionItems" (数组), "prediction"。内容全部中文。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        // Fix: Using responseSchema is the recommended way to ensure structured JSON output.
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            actionItems: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            prediction: { type: Type.STRING }
          },
          required: ["summary", "actionItems", "prediction"]
        }
      }
    });

    // Fix: Access .text property directly (do not call as method).
    const text = response.text?.trim() || '{}';
    return JSON.parse(text) as InsightResponse;
  } catch (error) {
    console.error("Gemini Insight Error:", error);
    // Graceful fallback logic for robust UI performance.
    return {
      summary: "由于数据流波动，无法生成精准 AI 洞察。但初步观察显示，AG 平台在重度玩家人群中渗透率有待提升。",
      actionItems: ["检查高潜人群的定向出价是否过低", "对比抖音端高点击素材，优化 AG 详情页素材", "针对余额预警客户启动自助充值引导"],
      prediction: "预计未来两周行业竞争加剧，建议在保持现有 CPA 水平下，通过增加定向标签获取增量。"
    };
  }
};

export enum ClientStage {
  PROSPECT = 'PROSPECT', 
  ACTIVE = 'ACTIVE',     
  CHURN = 'CHURN',       
}

export interface MetricPoint {
  date: string;
  value: number;
  comparison?: number; 
  ideal?: number;      
  forecast?: number;   
}

export interface AppInMatrix {
  id: string;
  name: string;
  icon: string;
  status: 'ONLINE' | 'OFFLINE' | 'UPDATING';
  dailySpend: number;
  cvr: number;
}

export interface ChannelMetrics {
  channel: string;
  downloads: number;
  activations: number;
  retention1d: number; // %
  retention7d: number; // %
  retention30d: number; // %
}

export interface SegmentChannelData {
  segment: string;
  ag: number;
  douyin: number;
  kuaishou: number;
  wechat: number;
}

export interface AdTaskMetrics {
  id: string;
  taskName: string;
  impressions: number;
  clicks: number;
  activations: number;
  conversions: number;
  ctr: number;
  cvr: number;
}

export interface ClientProfile {
  id: string;
  name: string;
  logo: string;
  industry: string;
  stage: ClientStage;
  tier: 'S' | 'A' | 'B';

  corporateEntity: string;
  accountRating: string;
  salesOwner: string;
  opsOwner: string;
  appMatrix: AppInMatrix[];
  financials: {
    balance: number;
    creditLimit: number;
    rebateRate: number;
    walletRunwayDays: number;
  };

  hourlySpend: MetricPoint[];
  dailySpendTrend: MetricPoint[];
  budgetUtilization: number;
  spendVelocity: 'Normal' | 'Slow' | 'Fast';
  lostImpressionsByBudget: number;

  funnel: { stage: string; value: number; rate: number }[];
  attribution: { source: string; impressions: number; conversions: number; rate: number }[];
  adTasks: AdTaskMetrics[]; // 新增：投放任务级别数据

  creativeFatigue: {
    name: string;
    ctr: number;
    fatigueIndex: number;
    status: 'Healthy' | 'Warning' | 'Stale';
  }[];

  distributionShare: { platform: string; value: number; count: number }[];
  multiChannelQuality: ChannelMetrics[];
  segmentGaps: SegmentChannelData[];

  churnProbability7d: number;
  churnProbability14d: number;
  budgetBottleneck: string;
  cpaAnomaly: {
    actual: number;
    target: number;
    deviation: number;
  };
}

export interface PlatformStats {
  healthScore: number;
  realtime: {
    spend: number;
    ecpm: number;
    ctr: number;
    cvr: number;
    fillRate: number;
    comparisons: {
      yesterday: number;
      lastWeek: number;
    };
  };
  segments: {
    lifecycle: { label: string; value: number; color: string }[];
    tierDistribution: { label: string; count: number; color: string }[];
  };
  heatmap: {
    category: string;
    bidPrice: number;
    trafficVolume: number;
  }[];
  risks: {
    anomalies: {
      id: string;
      name: string;
      type: 'CVR_DROP' | 'SPEND_PLUMMET' | 'FILL_RATE_LOW';
      value: string;
      severity: 'high' | 'medium';
    }[];
    complianceViolations: number;
    appRemovals: number;
    budgetExhaustionRate: number;
  };
  forecasts: {
    traffic: MetricPoint[];
    biddingTrends: {
      category: string;
      current: number;
      trend: 'up' | 'down' | 'stable';
      change: number;
    }[];
  };
}

