import React from 'react';
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  BarChart,
  Bar,
  Cell,
  PieChart,
  Pie,
  LineChart,
  Line,
} from 'recharts';
import { MetricPoint } from '../types';

interface TrendChartProps {
  data: MetricPoint[];
  dataKey: string;
  color: string;
  showForecast?: boolean;
}

export const TrendChart: React.FC<TrendChartProps> = ({ data, dataKey, color, showForecast }) => {
  return (
    <ResponsiveContainer width="100%" height={250}>
      <AreaChart data={data} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
        <defs>
          <linearGradient id={`color${dataKey}`} x1="0" y1="0" x2="0" y2="1">
            <stop offset="5%" stopColor={color} stopOpacity={0.8}/>
            <stop offset="95%" stopColor={color} stopOpacity={0}/>
          </linearGradient>
        </defs>
        <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{fontSize: 10}} />
        <YAxis axisLine={false} tickLine={false} tick={{fontSize: 10}} />
        <CartesianGrid vertical={false} strokeDasharray="3 3" stroke="#f0f0f0" />
        <Tooltip 
          contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
        />
        <Area 
          type="monotone" 
          dataKey="value" 
          stroke={color} 
          fillOpacity={1} 
          fill={`url(#color${dataKey})`} 
          name="数值"
        />
        {showForecast && (
             <Area 
             type="monotone" 
             dataKey="forecast" 
             stroke={color} 
             strokeDasharray="5 5"
             fill="none"
             name="预测值"
           />
        )}
      </AreaChart>
    </ResponsiveContainer>
  );
};

export const SparklineChart: React.FC<{data: MetricPoint[], color: string}> = ({ data, color }) => {
  return (
    <ResponsiveContainer width="100%" height={40}>
      <AreaChart data={data} margin={{ top: 0, right: 0, left: 0, bottom: 0 }}>
        <Area 
          type="monotone" 
          dataKey="value" 
          stroke={color} 
          strokeWidth={2}
          fill={color} 
          fillOpacity={0.1} 
        />
      </AreaChart>
    </ResponsiveContainer>
  );
};

export const MultiLineChart: React.FC<{data: any[], lines: any[]}> = ({ data, lines }) => {
  return (
    <ResponsiveContainer width="100%" height={250}>
      <LineChart data={data}>
        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
        <XAxis dataKey="date" tick={{fontSize: 10}} />
        <YAxis tick={{fontSize: 10}} />
        <Tooltip />
        <Legend />
        {lines.map((line) => (
          <Line key={line.key} type="monotone" dataKey={line.key} stroke={line.color} strokeWidth={2} name={line.name} dot={{r: 3}} />
        ))}
      </LineChart>
    </ResponsiveContainer>
  );
};

export const DonutChart: React.FC<{data: any[], height?: number}> = ({ data, height = 320 }) => {
  return (
    <ResponsiveContainer width="100%" height={height}>
      <PieChart margin={{ top: 0, bottom: 40 }}>
        <Pie
          data={data}
          innerRadius="50%"
          outerRadius="75%"
          paddingAngle={5}
          dataKey="value"
          nameKey="label"
          label={({ label, value }) => `${label} (${value}%)`}
        >
          {data.map((entry, index) => (
            <Cell key={`cell-${index}`} fill={entry.color} />
          ))}
        </Pie>
        <Tooltip 
          formatter={(value: number, name: string, props: any) => {
             const count = props?.payload?.count;
             return [`${value}% ${count ? '(' + (count/10000).toFixed(1) + 'w)' : ''}`, name];
          }}
          contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
        />
        <Legend 
            verticalAlign="bottom"
            align="center"
            wrapperStyle={{ paddingTop: '20px' }}
            formatter={(value) => {
                const item = data.find(d => d.label === value);
                return <span className="text-gray-600 text-xs font-semibold">{value} ({item?.value}%)</span>;
            }}
        />
      </PieChart>
    </ResponsiveContainer>
  );
};

export const FunnelChart: React.FC<{data: any[]}> = ({ data }) => {
  return (
    <ResponsiveContainer width="100%" height={250}>
      <BarChart layout="vertical" data={data} margin={{ left: 20, right: 20 }}>
        <XAxis type="number" hide />
        <YAxis dataKey="stage" type="category" tick={{fontSize: 12, fontWeight: 600}} width={60} />
        <Tooltip />
        <Bar dataKey="value" fill="#6366f1" barSize={35} radius={[0, 4, 4, 0]} />
      </BarChart>
    </ResponsiveContainer>
  );
};

