/**
 * 通用图片加载组件，处理加载失败情况
 */
const ImageWithFallback: React.FC<{ 
  src: string; 
  alt: string; 
  className?: string; 
  fallbackText?: string;
  size?: number;
}> = ({ src, alt, className, fallbackText, size = 16 }) => {
  const [error, setError] = useState(false);

  if (error || !src) {
    return (
      <div className={`${className} bg-slate-100 flex items-center justify-center text-slate-400 border border-slate-200 overflow-hidden`}>
        {fallbackText ? (
          <span className="font-bold text-xs">{fallbackText.substring(0, 1).toUpperCase()}</span>
        ) : (
          <ImageIcon size={size} />
        )}
      </div>
    );
  }

  return (
    <img 
      src={src} 
      alt={alt} 
      className={className} 
      onError={() => setError(true)} 
    />
  );
};

