/**
 * 垂直漏斗图组件
 * 布局：曝光 -> 点击 -> 下载 -> 激活 -> 转化
 */
export const FunnelChart: React.FC<{data: any[]}> = ({ data }) => {
  // 颜色配置
  const colors = [
    '#1e293b', // 曝光 - 深蓝灰
    '#334155', // 点击
    '#475569', // 下载
    '#6366f1', // 激活 - 亮紫
    '#4f46e5', // 转化 - 亮蓝
  ];

  return (
    <div className="flex flex-col items-center w-full py-4 space-y-4">
      {data.map((item, index) => {
        // 计算宽度：基于最大值的比例，但不小于一定宽度
        const maxWidth = 100;
        const width = Math.max(40, (item.value / data[0].value) * maxWidth);

        return (
          <React.Fragment key={item.stage}>
            <div className="flex flex-col items-center w-full group">
              <div 
                className="relative flex items-center justify-center h-14 rounded-2xl shadow-sm transition-all duration-300 group-hover:shadow-md border border-white/10"
                style={{ 
                  width: `${width}%`, 
                  backgroundColor: colors[index],
                  color: 'white'
                }}
              >
                <div className="absolute left-6 font-black text-xs uppercase tracking-widest opacity-60">
                  {item.stage}
                </div>
                <div className="text-center">
                  <div className="text-lg font-black tracking-tight">{item.value.toLocaleString()}</div>
                </div>
                {index > 0 && (
                  <div className="absolute -right-16 bg-blue-50 text-blue-600 px-2 py-1 rounded-lg text-[10px] font-black border border-blue-100 shadow-sm">
                    {item.rate}%
                  </div>
                )}
              </div>

              {/* 连接箭头 */}
              {index < data.length - 1 && (
                <div className="flex flex-col items-center my-1">
                   <ChevronDown size={20} className="text-slate-300 animate-bounce" />
                </div>
              )}
            </div>
          </React.Fragment>
        );
      })}
    </div>
  );
};

