/**
 * 垂直漏斗图组件
 * 布局：曝光 -> 点击 -> 下载 -> 激活 -> 转化
 * 优化：通过宽度递减显式呈现漏斗形态
 */
export const FunnelChart: React.FC<{data: any[]}> = ({ data }) => {
  // 颜色配置：从深到亮体现漏斗深度
  const colors = [
    '#1e293b', // 曝光 - 深蓝灰
    '#334155', // 点击
    '#475569', // 下载
    '#6366f1', // 激活 - 亮紫
    '#4f46e5', // 转化 - 亮蓝
  ];

  return (
    <div className="flex flex-col items-center w-full py-4 space-y-4">
      {data.map((item, index) => {
        // 宽度计算：不仅仅是数值比例，还要结合索引进行“阶梯式”强制递减，保证视觉漏斗感
        // 计算公式：(数值占比 * 权重) + (层级基础宽度)
        const baseWidth = 100 - (index * 15); // 每一层至少比上一层视觉上缩窄 15%
        const ratio = (item.value / data[0].value);
        const width = Math.max(25, baseWidth * (0.6 + 0.4 * ratio)); 

        return (
          <React.Fragment key={item.stage}>
            <div className="flex flex-col items-center w-full group">
              <div 
                className="relative flex items-center justify-center h-14 rounded-2xl shadow-sm transition-all duration-300 group-hover:shadow-md border border-white/10 overflow-hidden"
                style={{ 
                  width: `${width}%`, 
                  backgroundColor: colors[index],
                  color: 'white'
                }}
              >
                {/* 装饰层：左侧标签 */}
                <div className="absolute left-6 font-black text-[10px] uppercase tracking-widest opacity-40">
                  {item.stage}
                </div>

                <div className="text-center">
                  <div className="text-lg font-black tracking-tight">{item.value.toLocaleString()}</div>
                </div>

                {/* 右侧比率 */}
                {index > 0 && (
                  <div className="absolute right-4 bg-white/20 backdrop-blur-md px-2 py-0.5 rounded-lg text-[10px] font-black border border-white/10">
                    {item.rate}%
                  </div>
                )}
              </div>

              {/* 连接箭头 */}
              {index < data.length - 1 && (
                <div className="flex flex-col items-center my-0.5">
                   <ChevronDown size={18} className="text-slate-200/50" />
                </div>
              )}
            </div>
          </React.Fragment>
        );
      })}
    </div>
  );
};

