 * 布局：曝光 -> 点击 -> 下载 -> 激活 -> 转化
 * 优化：显著递减效果，转化率外置
 */
export const FunnelChart: React.FC<{data: any[]}> = ({ data }) => {
  const colors = [
    '#0f172a', // 曝光
