                {item.stage}
              </div>
              <div className="text-xl font-black tracking-tight drop-shadow-sm">
                {item.value.toLocaleString()}
              </div>

              {/* 外置转化率：放置在图块右侧 */}
              {index > 0 && (
                <div className="absolute -right-24 flex items-center gap-2 group-hover:translate-x-1 transition-transform">
                  <ArrowRight size={14} className="text-slate-300" />
                  <div className="bg-white border border-slate-100 shadow-sm px-3 py-1 rounded-full text-[11px] font-black text-blue-600">
                    {item.rate}%
                  </div>
                </div>
              )}
            </div>

            {/* 连接线 */}
            {index < data.length - 1 && (
              <div className="my-1 flex flex-col items-center">
                 <ChevronDown size={18} className="text-slate-200" />
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
};

