/**
 * 垂直漏斗图组件
 * 优化：显著递减，文字字号加大并贴近色块，移除箭头
 */
export const FunnelChart: React.FC<{data: any[]}> = ({ data }) => {
  const colors = [
    '#0f172a', // 曝光
    '#1e293b', // 点击
    '#334155', // 下载
    '#6366f1', // 激活
    '#4f46e5', // 转化
  ];

  return (
    <div className="flex flex-col items-center w-full py-16 space-y-8">
      {data.map((item, index) => {
        // 增强的阶梯式递减逻辑：每一层强制减少 15% 宽度基准
        const stepReduction = index * 15;
        // 计算当前节点相对于最大节点的数值比例，用于微调
        const valueRatio = item.value / data[0].value;
        // 最终宽度 = 基准收窄值 * (数值比例权重)
        const width = Math.max(15, (100 - stepReduction) * (0.3 + 0.7 * valueRatio));

        return (
          <div key={item.stage} className="relative flex flex-col items-center w-full group">

            {/* 核心容器 */}
            <div className="relative flex items-center justify-center w-full max-w-xl">

              {/* 左侧阶段名称：字号加大，位置更近 */}
              <div className="absolute left-[-15px] transform -translate-x-full opacity-90 group-hover:opacity-100 transition-all">
                <span className="text-lg font-black uppercase tracking-widest text-slate-800 whitespace-nowrap">
                  {item.stage}
                </span>
              </div>

              {/* 主图块 */}
              <div 
                className="relative flex items-center justify-center h-20 rounded-2xl shadow-2xl transition-all duration-300 group-hover:scale-[1.08] border border-white/10"
                style={{ 
                  width: `${width}%`, 
                  backgroundColor: colors[index],
                  color: 'white'
                }}
              >
                <div className="text-3xl font-black tracking-tighter drop-shadow-2xl">
                  {item.value.toLocaleString()}
                </div>
              </div>

              {/* 右侧转化率：字号加大，紧贴色块，移除图标 */}
              {index > 0 && (
                <div className="absolute right-[-15px] transform translate-x-full opacity-100 transition-all">
                  <div className="bg-white border-2 border-indigo-200 shadow-2xl px-6 py-2 rounded-2xl text-xl font-black text-indigo-700 ring-4 ring-indigo-50/50">
                    {item.rate}%
                  </div>
                </div>
              )}
            </div>

            {/* 连接线 */}
            {index < data.length - 1 && (
              <div className="my-2 flex flex-col items-center opacity-40 group-hover:opacity-100 transition-opacity">
                 <ChevronDown size={28} className="text-slate-400 animate-bounce" />
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
};

