 * 布局：曝光 -> 点击 -> 下载 -> 激活 -> 转化
 * 优化：强制最小宽度为 35% 确保文字在内，同时指数化宽度以体现漏斗收窄效果
 */
export const FunnelChart: React.FC<{data: any[]}> = ({ data }) => {
  const colors = [
    '#0f172a', // 曝光
    '#1e293b', // 点击
    '#334155', // 下载
    '#6366f1', // 激活
    '#4f46e5', // 转化
  ];

  return (
    <div className="flex flex-col items-center w-full py-16 space-y-10">
      {data.map((item, index) => {
        /**
         * 宽度逻辑重塑：
         * 1. 曝光固定 100%
         * 2. 后续节点根据比例和 index 计算，但 Math.max 设为 35% 保证 text-2xl 级别数字不溢出
         */
        const valueRatio = item.value / data[0].value;
        const width = index === 0 ? 100 : Math.max(35, 100 * Math.pow(valueRatio, 0.25) * (1 - index * 0.04));

        return (
          <div key={item.stage} className="relative flex flex-col items-center w-full group">

            {/* 内容容器 */}
            <div className="relative flex items-center justify-center w-full max-w-2xl">

