/**
 * 抓取企业百科信息：发展历程与高管团队
 */
export const fetchCorporateWiki = async (companyName: string): Promise<CorporateWiki> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    请通过互联网搜索抓取并汇总“${companyName}”的企业百科信息。
    需要包括：
    1. 发展历程中的核心里程碑（按年份，至少5个重要事件）。
    2. 现任核心高管团队（姓名、职位及简单背景）。

    输出格式要求：必须为严格的 JSON 格式。
    JSON 结构：
    {
      "milestones": [{"year": "年份", "event": "事件简述", "detail": "详细描述"}],
      "executives": [{"name": "姓名", "title": "职位", "background": "背景简介"}]
    }
    同时请确保能够获取到参考来源的 URL。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            milestones: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  year: { type: Type.STRING },
                  event: { type: Type.STRING },
                  detail: { type: Type.STRING }
                }
              }
            },
            executives: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  title: { type: Type.STRING },
                  background: { type: Type.STRING }
                }
              }
            }
          }
        }
      }
    });

    const text = response.text?.trim() || '{}';
    const baseData = JSON.parse(text);

    // 提取搜索来源链接 (Grounding Chunks)
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        title: chunk.web?.title || '参考来源',
        uri: chunk.web?.uri || ''
      }))
      .filter((s: any) => s.uri) || [];

    return {
      ...baseData,
      sources
    };
  } catch (error) {
    console.error("Fetch Corporate Wiki Error:", error);
    // 降级静态数据（度小满相关）
    return {
      milestones: [
        { year: "2015", event: "百度金融成立", detail: "百度宣布组建金融服务事业群组（FSG），由朱光全面负责。" },
        { year: "2018", event: "品牌升级为度小满", detail: "百度金融正式启用“度小满金融”品牌，实现独立运营。" },
        { year: "2019", event: "启动小微专项计划", detail: "发布“小微加油站”计划，深耕普惠金融。" },
        { year: "2021", event: "获得消费金融牌照", detail: "旗下哈尔滨哈银消费金融公司获批成立。" },
        { year: "2023", event: "发布“轩辕”金融大模型", detail: "正式开源千亿级金融大模型，推动金融行业 AI 化。" }
      ],
      executives: [
        { name: "朱光", title: "度小满 CEO", background: "曾任百度高级副总裁，度小满创始负责人，金融科技行业领军人物。" },
        { name: "谢贤林", title: "度小满 CTO", background: "负责公司技术架构、智能风控及大模型技术研发。" }
      ],
      sources: [
        { title: "度小满金融官网", uri: "https://www.duxiaoman.com" },
        { title: "百度百科-度小满金融", uri: "https://baike.baidu.com/item/度小满金融" }
      ]
    };
  }
};

/**
 * 原有的 AI 洞察分析
 */
export const generateClientInsight = async (client: ClientProfile): Promise<InsightResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const agQuality = client.multiChannelQuality.find(q => q.channel.includes('AG')) || client.multiChannelQuality[0];
  const douyinQuality = client.multiChannelQuality.find(q => q.channel === '抖音');

  const prompt = `
    请作为分析专家分析以下广告主的数据：
    客户: ${client.name} | 行业: ${client.industry} | 级别: ${client.tier}级
    消耗利用率: ${client.budgetUtilization}% | 7日流失概率: ${client.churnProbability7d}%

    输出格式: JSON 包含 "summary", "actionItems", "prediction"。全部中文。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            actionItems: { type: Type.ARRAY, items: { type: Type.STRING } },
            prediction: { type: Type.STRING }
          }
        }
      }
    });

    return JSON.parse(response.text?.trim() || '{}') as InsightResponse;
  } catch (e) {
    return {
      summary: "数据分析目前不可用。",
      actionItems: ["请检查数据连接"],
      prediction: "无预测"
    };
  }
};

