import { GoogleGenAI, Type } from "@google/genai";
import { ClientProfile, InsightResponse, CorporateWiki, AppIntelligence } from "../types";

/**
 * 抓取 App 全网情报与 AI 洞察
 */
export const fetchAppIntelligence = async (appName: string): Promise<AppIntelligence> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    请针对 App “${appName}” 进行全网情报检索：
    1. 抓取近期的发展历程（里程碑）。
    2. 汇总近 30 天的动态（版本更新、新闻、融资、代言等）。
    3. 基于情报给出 AI 洞察：该 App 目前的战略重心是什么？对我方应用商店销售有什么建议？

    输出要求：JSON 格式。
    结构：
    {
      "milestones": [{"date": "日期", "title": "事件", "detail": "描述"}],
      "recentDynamics": [{"date": "日期", "content": "动态详情", "source": "来源"}],
      "aiInsight": "深入的战略洞察文案"
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            milestones: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  date: { type: Type.STRING },
                  title: { type: Type.STRING },
                  detail: { type: Type.STRING }
                }
              }
            },
            recentDynamics: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  date: { type: Type.STRING },
                  content: { type: Type.STRING },
                  source: { type: Type.STRING }
                }
              }
            },
            aiInsight: { type: Type.STRING }
          }
        }
      }
    });

    const data = JSON.parse(response.text?.trim() || '{}');
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((c: any) => ({
      title: c.web?.title || '来源',
      uri: c.web?.uri || ''
    })) || [];

    return { ...data, sources };
  } catch (e) {
    console.error(e);
    return {
      milestones: [{ date: "2024-03", title: "版本大更新", detail: "度小满金融 V6.0 发布" }],
      recentDynamics: [{ date: "2024-03-20", content: "宣布开源千亿级金融大模型轩辕", source: "36Kr" }],
      aiInsight: "AI 洞察：该 App 近期重心在于“金融 AI 化”，建议销售推荐“智能外呼”与“高净值人群定向”广告位。",
      sources: []
    };
  }
};

export const fetchCorporateWiki = async (companyName: string): Promise<CorporateWiki> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `抓取“${companyName}”的企业百科信息，包括发展历程和高管。输出 JSON。`;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: 'application/json'
      }
    });
    return JSON.parse(response.text?.trim() || '{}');
  } catch (e) {
    return { milestones: [], executives: [], sources: [] };
  }
};

export const generateClientInsight = async (client: ClientProfile): Promise<InsightResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `分析广告主 ${client.name} 的数据。输出 JSON：summary, actionItems, prediction。`;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { responseMimeType: 'application/json' }
    });
    return JSON.parse(response.text?.trim() || '{}');
  } catch (e) {
    return { summary: "不可用", actionItems: [] };
  }
};

