import React from 'react';
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  LineChart,
  Line,
  Cell,
  PieChart,
  Pie,
} from 'recharts';
import { MetricPoint } from '../types';
import { ChevronDown } from 'lucide-react';

interface TrendChartProps {
  data: MetricPoint[];
  dataKey: string;
  color: string;
  showForecast?: boolean;
}

export const TrendChart: React.FC<TrendChartProps> = ({ data, dataKey, color, showForecast }) => {
  return (
    <ResponsiveContainer width="100%" height="100%">
      <AreaChart data={data} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
        <XAxis 
          dataKey="date" 
          axisLine={false} 
          tickLine={false} 
          tick={{fontSize: 10, fill: '#94a3b8', fontWeight: 700}} 
        />
        <YAxis 
          axisLine={false} 
          tickLine={false} 
          tick={{fontSize: 10, fill: '#94a3b8', fontWeight: 700}} 
        />
        <CartesianGrid vertical={false} stroke="#f1f5f9" />
        <Tooltip 
          contentStyle={{ 
            borderRadius: '4px', 
            border: '1px solid #e2e8f0', 
            boxShadow: 'none',
            fontSize: '12px',
            fontWeight: 800
          }}
        />
        <Area 
          type="monotone" 
          dataKey="value" 
          stroke={color} 
          strokeWidth={2}
          fill={color} 
          fillOpacity={0.1} 
          name="VALUE"
        />
        {showForecast && (
             <Area 
             type="monotone" 
             dataKey="forecast" 
             stroke={color} 
             strokeDasharray="4 4"
             fill="none"
             name="FORECAST"
           />
        )}
      </AreaChart>
    </ResponsiveContainer>
  );
};

