    const parseNum = (val: string) => {
      if (val.includes('亿')) return parseFloat(val) * 100000000;
      if (val.includes('w')) return parseFloat(val) * 10000;
      return parseFloat(val);
    };
    let maxDownloads = { val: -1, platform: '' };
    let maxMau = { val: -1, platform: '' };
    let maxRating = { val: -1, platform: '' };
    app.platformMatrix.forEach(item => {
      const d = parseNum(item.downloads);
      const m = parseNum(item.mau);
      if (d > maxDownloads.val) { maxDownloads = { val: d, platform: item.platform }; }
      if (m > maxMau.val) { maxMau = { val: m, platform: item.platform }; }
      if (item.rating > maxRating.val) { maxRating = { val: item.rating, platform: item.platform }; }
    });
    return { maxDownloads, maxMau, maxRating };
