const generateQualityData = (days: number, type: 'retention' | 'uninstall') => {
  const baseData = {
    retention: { AG: 48, Yingyongbao: 38, Douyin: 32, Wechat: 40, Baidu: 35, target: 45 },
    uninstall: { AG: 11, Yingyongbao: 18, Douyin: 25, Wechat: 15, Baidu: 20, target: 12 }
  };
  const factor = days === 1 ? 1 : days === 3 ? 0.8 : days === 7 ? 0.6 : 0.45;
  const variance = type === 'retention' ? 6 : 4;

  return ['10月', '11月', '12月', '01月', '02月', '03月'].map((month, idx) => {
    const agOscillation = idx === 1 ? -4 : idx === 4 ? 5 : idx === 5 ? 2 : 0;
    return {
      month,
      AG: (baseData[type].AG * factor) + agOscillation + (Math.random() * 2),
      Yingyongbao: (baseData[type].Yingyongbao * factor) + (Math.random() * variance),
      Douyin: (baseData[type].Douyin * factor) + (Math.random() * variance),
      Wechat: (baseData[type].Wechat * factor) + (Math.random() * variance),
      Baidu: (baseData[type].Baidu * factor) + (Math.random() * variance),
      target: baseData[type].target * factor
    };
  });
};

