                {/* 强化目标红线：极粗线宽 + 巨大加粗标签 */}
                <ReferenceLine 
                  y={0.6} 
                  stroke="#ef4444" 
                  strokeWidth={6} 
                  strokeDasharray="12 6"
                  label={{ 
                    position: 'right', 
                    value: `份额目标: 60%`, 
                    fill: '#ef4444', 
                    fontSize: 22, 
                    fontWeight: 900, 
                    offset: 30 
                  }} 
                />

                {/* 堆叠面积图：确保没有蓝色的 Line 层 */}
                <Area type="monotone" dataKey="AG" stackId="1" name="AG (我方核心份额)" stroke="none" fill="#1e293b" fillOpacity={0.95} />
                <Area type="monotone" dataKey="Yingyongbao" stackId="1" name="应用宝" stroke="none" fill="#7dd3fc" fillOpacity={0.7} />
                <Area type="monotone" dataKey="Douyin" stackId="1" name="抖音" stroke="none" fill="#f59e0b" fillOpacity={0.7} />
                <Area type="monotone" dataKey="Wechat" stackId="1" name="微信小程序" stroke="none" fill="#86efac" fillOpacity={0.7} />
                <Area type="monotone" dataKey="Baidu" stackId="1" name="百度" stroke="none" fill="#c4b5fd" fillOpacity={0.7} />
              </ComposedChart>
           </ResponsiveContainer>
        </div>
        <div className="mt-12 p-8 bg-blue-50 border border-blue-100 rounded-lg shadow-sm border-l-4 border-l-blue-600">
           <h5 className="text-[11px] font-black text-blue-600 uppercase mb-4 tracking-widest flex items-center gap-2">
             <Activity size={16}/> 市场份额深度诊断
           </h5>
           <div className="space-y-4 text-[15px] font-bold text-slate-800 leading-relaxed">
             <p>通过 100% 堆叠视图可见，<span className="text-blue-600">AG (我方)</span> 的市场份额正处于剧烈博弈期。在 11月 与 3月 成功实现<span className="text-emerald-600">上穿 60% 目标线</span>。</p>
             <p>但在 12月 及 2月 出现明显的<span className="text-red-600">下穿回调</span>，AI 识别原因为竞品在该周期内加大了拉新补贴。建议在份额下穿 60% 红线时，触发自动补偿计划。</p>
           </div>
        </div>
      </section>

      {/* 5. 渠道分发质量监控 */}
      <section className="bg-white rounded border border-slate-200 p-8 mb-6">
        {renderSectionHeader("渠道分发质量监控", <ShieldHalf size={18}/>)}

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
           <div className="space-y-6">
              <div className="flex items-center justify-between">
                 <h4 className="text-[11px] font-black text-slate-900 uppercase tracking-widest flex items-center gap-2">
                    <Activity size={14} className="text-emerald-500"/> 渠道分发留存率趋势 (%)
                 </h4>
                 <div className="flex bg-slate-100 p-0.5 rounded border border-slate-200 shadow-inner">
                    {[1, 3, 7, 14].map(d => (
                      <button 
                        key={d} 
                        onClick={() => setRetentionDays(d)}
                        className={`px-3 py-1 text-[9px] font-black uppercase rounded transition-all ${retentionDays === d ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                      >
                        {d}D
                      </button>
                    ))}
                 </div>
              </div>
              <div className="h-[320px] bg-slate-50/30 rounded-lg border border-slate-100 p-4">
                 <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={currentRetentionData}>
                       <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                       <XAxis dataKey="month" tick={{fontSize: 9, fontWeight: 900, fill: '#94a3b8'}} axisLine={false} tickLine={false} />
                       <YAxis tick={{fontSize: 9, fontWeight: 900, fill: '#94a3b8'}} axisLine={false} tickLine={false} domain={[0, 60]} />
                       <Tooltip contentStyle={{fontSize: '10px', borderRadius: '6px', border: '1px solid #e2e8f0'}} />
                       <Legend iconType="circle" wrapperStyle={{fontSize: '9px', fontWeight: 900, paddingTop: '15px'}} />
                       <ReferenceLine y={currentRetentionData[0].target} stroke="#ef4444" strokeWidth={3} strokeDasharray="6 4" />
                       <Line type="monotone" dataKey="AG" name="AG 我方" stroke="#1e293b" strokeWidth={4} dot={{r: 4, strokeWidth: 2, fill: '#fff'}} />
                       <Line type="monotone" dataKey="Yingyongbao" name="应用宝" stroke="#7dd3fc" strokeWidth={2} dot={false} strokeDasharray="4 2" />
                       <Line type="monotone" dataKey="Douyin" name="抖音" stroke="#f59e0b" strokeWidth={2} dot={false} strokeDasharray="4 2" />
                    </LineChart>
                 </ResponsiveContainer>
              </div>
           </div>

           <div className="space-y-6">
              <div className="flex items-center justify-between">
                 <h4 className="text-[11px] font-black text-slate-900 uppercase tracking-widest flex items-center gap-2">
                    <ArrowDownCircle size={14} className="text-rose-500"/> 渠道分发卸载率监控 (%)
                 </h4>
                 <div className="flex bg-slate-100 p-0.5 rounded border border-slate-200 shadow-inner">
                    {[1, 3, 7, 14].map(d => (
                      <button 
                        key={d} 
                        onClick={() => setUninstallDays(d)}
                        className={`px-3 py-1 text-[9px] font-black uppercase rounded transition-all ${uninstallDays === d ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                      >
                        {d}D
                      </button>
                    ))}
                 </div>
              </div>
              <div className="h-[320px] bg-slate-50/30 rounded-lg border border-slate-100 p-4">
                 <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={currentUninstallData}>
                       <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                       <XAxis dataKey="month" tick={{fontSize: 9, fontWeight: 900, fill: '#94a3b8'}} axisLine={false} tickLine={false} />
                       <YAxis tick={{fontSize: 9, fontWeight: 900, fill: '#94a3b8'}} axisLine={false} tickLine={false} domain={[0, 40]} />
                       <Tooltip contentStyle={{fontSize: '10px', borderRadius: '6px', border: '1px solid #e2e8f0'}} />
                       <Legend iconType="circle" wrapperStyle={{fontSize: '9px', fontWeight: 900, paddingTop: '15px'}} />
                       <ReferenceLine y={currentUninstallData[0].target} stroke="#ef4444" strokeWidth={3} strokeDasharray="6 4" />
                       <Line type="monotone" dataKey="AG" name="AG 我方" stroke="#1e293b" strokeWidth={4} dot={{r: 4, strokeWidth: 2, fill: '#fff'}} />
                       <Line type="monotone" dataKey="Yingyongbao" name="应用宝" stroke="#7dd3fc" strokeWidth={2} dot={false} />
                       <Line type="monotone" dataKey="Baidu" name="百度" stroke="#c4b5fd" strokeWidth={2} dot={false} />
                    </LineChart>
                 </ResponsiveContainer>
              </div>
           </div>
        </div>

        <div className="mt-10 p-8 bg-slate-900 rounded-xl text-white relative overflow-hidden">
           <div className="absolute top-0 right-0 p-8 opacity-5"><BrainCircuit size={120}/></div>
           <div className="flex items-center gap-3 mb-6">
              <div className="p-2 bg-blue-600 rounded">
                <Sparkles size={18} className="text-white"/>
              </div>
              <h5 className="text-[12px] font-black uppercase tracking-widest text-blue-400">AI 分发质量智能诊断报告</h5>
           </div>
           <div className="grid grid-cols-1 md:grid-cols-3 gap-8 relative z-10">
              <div className="space-y-3">
                 <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest">留存分析</div>
                 <p className="text-sm font-bold leading-relaxed">AG 渠道表现稳定在上穿目标线，主要得益于版本迭代。当前 7D 留存率处于高位。</p>
              </div>
              <div className="space-y-3">
                 <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest">卸载预警</div>
                 <p className="text-sm font-bold leading-relaxed">卸载率整体维持在 12% 容忍上限下方。11月曾出现穿刺预警，现已平稳。</p>
              </div>
              <div className="space-y-3">
                 <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest">竞对博弈</div>
                 <p className="text-sm font-bold leading-relaxed">与抖音相比，我方用户粘性显著更高，但首日转化率略逊，建议优化冷启动链路。</p>
              </div>
